function modalToggle(e,o){e.style.display=o}const btnOpenModal=document.querySelectorAll("[data-show-modal]"),modalWindow=document.querySelector("[data-modal]");for(let e of btnOpenModal)e.addEventListener("click",()=>{modalToggle(modalWindow,"block")});const crossCloseModal=document.querySelectorAll("[data-close-modal]");for(let e of crossCloseModal)e.addEventListener("click",e=>{modalToggle(e.target.closest("[data-modal]"),"none")});const reviewsSlider=new Swiper(".reviews",{navigation:{prevEl:".reviews__nav-prev",nextEl:".reviews__nav-next"},simulateTouch:!0,touchRatio:1,touchAngle:45,grabCursor:!0,loop:!0,slidesPerView:1,spaceBetween:90,autoplay:{delay:3e3}}),questions=document.querySelectorAll(".question");